SELECT 
FROM users u

WHERE 1 = 1

    AND (u.email LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%'))


    AND u.status = #{status}


    AND u.role = #{role}

ORDER BY u.created_at DESC
LIMIT #{limit}

SELECT 
FROM users u

WHERE u.id = #{id}

SELECT *
FROM user_login_history
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT *
FROM user_status_history
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, user_id, email, purpose, expired_at, used, used_at, created_at
FROM email_verification
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, user_id, expired_at, revoked, revoked_at, ip_address, user_agent, created_at
FROM refresh_token
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, user_id, application_case_id, feature_type, status, model, input_tokens, output_tokens,
       token_usage, credit_used, error_message, created_at
FROM ai_usage_log
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

